import{_ as r}from"./chunks/logo.PPNoggWL.js";import{_ as t,o as a,c as o,ag as i}from"./chunks/framework.DQQHyi2x.js";const f=JSON.parse('{"title":"AtmosphericX Introduction","description":"","frontmatter":{"layout":"doc","next":{"text":"Installation","link":"/pages/installation/installation"},"prev":{"text":"Home","link":"/"}},"headers":[],"relativePath":"pages/installation/index.md","filePath":"pages/installation/index.md"}'),s={name:"pages/installation/index.md"};function n(l,e,c,d,h,p){return a(),o("div",null,[...e[0]||(e[0]=[i('<img src="'+r+'" alt="AtmosphericX Logo" width="200" style="display:block;margin:0 auto;"><small class="page-author">Written By: <b>KiyoWx</b> &amp; <b>StarflightWx</b></small><br><small class="last-updated">Last Updated: <b>Feb 27th, 2026</b></small><br><small class="version-made">Version: <b>8.0.0.021 (beta-pre-dashboard-testing)</b></small><br><br><h1 id="atmosphericx-introduction" tabindex="-1">AtmosphericX Introduction <a class="header-anchor" href="#atmosphericx-introduction" aria-label="Permalink to &quot;AtmosphericX Introduction&quot;">​</a></h1><hr><p>AtmosphericX is a modern, modular, and powerful weather dashboard and widget project designed to be self hosted for live streaming, storm spotting, storm chasing, meteorologists, first responders, or curious individuals who are concerned about weather conditions and safety.</p><h2 id="supported-features" tabindex="-1">Supported Features <a class="header-anchor" href="#supported-features" aria-label="Permalink to &quot;Supported Features&quot;">​</a></h2><ul><li><a href="https://www.weather.gov/nwws/" target="_blank" rel="noreferrer">NOAA Weather Wire Service Open-Interface</a> (Parser)</li><li><a href="https://www.weather.gov/documentation/services-web-api" target="_blank" rel="noreferrer">National Weather Service API</a> (Parser) <ul><li>Supports all VTEC, HVTEC, UGC, Offshore, and Plain Text Events</li></ul></li><li><a href="https://www.spotternetwork.org/" target="_blank" rel="noreferrer">SpotterNetwork</a> or <a href="https://rtirl.com/" target="_blank" rel="noreferrer">RealtimeIRL</a> GPS Tracking</li><li><a href="https://web.pulsepoint.org" target="_blank" rel="noreferrer">PulsePoint (Respond)</a> Event Manager</li><li>Local Storm Reports (SpotterNetwork or <a href="https://grlevelx.com/" target="_blank" rel="noreferrer">GibsonRidge</a>)</li><li>Mesoscale Discussions (<a href="https://weatherwise.app" target="_blank" rel="noreferrer">WeatherWise</a>)</li><li>Tropical Discussions / Events (<a href="https://weatherwise.app" target="_blank" rel="noreferrer">WeatherWise</a>)</li><li>ProbSevere Version 3 (<a href="https://cimss.ssec.wisc.edu/" target="_blank" rel="noreferrer">CIMSS</a>)</li><li>ProbTornado Version 3 (<a href="https://cimss.ssec.wisc.edu/" target="_blank" rel="noreferrer">CIMSS</a>)</li><li>ProjectWxEye Sonde (Credits: <a href="https://www.youtube.com/channel/UCqSk-ojoH2rgAuYadPLJgJA" target="_blank" rel="noreferrer">Vince Waelti</a>)</li><li>Nexrad Locations</li><li>NOAA Weather Radio (Built-in) (<a href="https://api.weatherusa.net" target="_blank" rel="noreferrer">WeatherUSA</a>)</li><li>Power Outage Statistics (US and US-Territories) (<a href="https://www.sdsweather.com/" target="_blank" rel="noreferrer">SDSWeather</a>)</li><li>Radar Omega Streams (<em>Not for Broadcast</em>) (<a href="https://www.sdsweather.com/" target="_blank" rel="noreferrer">SDSWeather</a>)</li><li>Tempest Station Integration (<a href="https://tempest.earth/tempest-home-weather-system/" target="_blank" rel="noreferrer">WeatherFlow-Tempest, Inc.</a>)</li><li>Built-in Placefiles for GibsonRidge Software, <a href="https://supercellwx.net/" target="_blank" rel="noreferrer">SupercellWx</a>, and more!</li><li>Event Customization (Sounds, Themes, Filtering)</li><li>Event Mock EAS Audios</li><li><s>Dashboard</s> (<code>SOON</code>)</li><li>Cache Control and HTTP(S) Security</li><li>Account Protection (argon2, sessions, and lockout)</li><li>RESTful API Ratelimiting</li><li>Cron Scheduling</li><li>Discord Webhook Configurations</li><li>Websocket Configurations and Priority</li><li>Streamer.bot Support</li><li><a href="https://weatherwise.app" target="_blank" rel="noreferrer">WeatherWise</a> Localized dBZ intensity</li><li>PolyWarn Tracking and Event Manager</li><li>Fully modular and limitless widget framework</li></ul><h2 id="documentation-vocab" tabindex="-1">Documentation Vocab <a class="header-anchor" href="#documentation-vocab" aria-label="Permalink to &quot;Documentation Vocab&quot;">​</a></h2><p>Throughout the documentation, you may see words that are commonly used. So we&#39;ve decided to give you a vocab on what they mean for the less technical individuals:</p><ul><li>Instance: This refers to your self hosted version of AtmosphericX.</li><li>Tunnel: The Cloudflare tunnel name.</li><li>Port: The network protocol AtmosphericX chooses to run on for web access.</li></ul><h2 id="disclaimer" tabindex="-1">Disclaimer <a class="header-anchor" href="#disclaimer" aria-label="Permalink to &quot;Disclaimer&quot;">​</a></h2><blockquote><p>AtmosphericX is an independent, open source project and is <strong>not</strong> affiliated with, endorsed by, or sponsored by any government agency, meteorological organization, emergency management service, or official weather provider. This project may reference, parse, or process publicly available weather data, including but <strong>not</strong> limited to services operated by the National Weather Service (NWS) and the National Oceanic and Atmospheric Administration (NOAA). All trademarks, service marks, and data rights remain the property of their respective owners. AtmosphericX is provided &quot;as is&quot;, without warranty of any kind, express or implied, including but <strong>not</strong> limited to:</p><ul><li>Accuracy or completeness of parsed weather data</li><li>Fitness for a particular purpose</li><li>Availability or reliability of upstream data sources</li><li>Protection against service interruptions or data delays</li></ul><p>AtmosphericX should <strong>not</strong> be relied upon for life safety decisions, emergency response coordination, aviation, marine navigation, or other critical applications. Always consult official sources for authoritative weather information. By using this software, you acknowledge and agree that the maintainers and contributors are <strong>not</strong> liable for any damages, losses, or consequences resulting from its use.</p></blockquote>',18)])])}const g=t(s,[["render",n]]);export{f as __pageData,g as default};
